def check_expression(exp):
    """Return True if parentheses/brackets/braces in `exp` are balanced, False otherwise."""
    stack = []
    # Mapping of closing to opening brackets
    pairs = {')': '(', ']': '[', '}': '{'}
    for ch in exp:
        if ch in '([{':
            stack.append(ch)
        elif ch in ')]}':
            if not stack or stack[-1] != pairs[ch]:
                return False
            stack.pop()
    return not stack

