def largest_subset(a):
    """
    Returns the size of the largest subset of `a` where every pair of numbers
    is divisible (i.e., for any two numbers x, y in the subset,
    either x % y == 0 or y % x == 0).
    """
    if not a:
        return 0
    a = sorted(a)
    n = len(a)
    dp = [1] * n  # each element alone forms a subset of size 1
    for i in range(n):
        for j in range(i):
            if a[i] % a[j] == 0:
                if dp[j] + 1 > dp[i]:
                    dp[i] = dp[j] + 1
    return max(dp) if dp else 0

def lcs_of_three(X, Y, Z):
    """Return one longest common subsequence of three strings."""
    n, m, p = len(X), len(Y), len(Z)
    # DP table of dimensions (n+1)*(m+1)*(p+1)
    dp = [[[0] * (p + 1) for _ in range(m + 1)] for _ in range(n + 1)]
    for i in range(1, n + 1):
        xi = X[i - 1]
        for j in range(1, m + 1):
            yj = Y[j - 1]
            for k in range(1, p + 1):
                if xi == yj == Z[k - 1]:
                    dp[i][j][k] = dp[i - 1][j - 1][k - 1] + 1
                else:
                    dp[i][j][k] = max(
                        dp[i - 1][j][k],
                        dp[i][j - 1][k],
                        dp[i][j][k - 1]
                    )
    # Reconstruct LCS
    i, j, k = n, m, p
    lcs_chars = []
    while i > 0 and j > 0 and k > 0:
        if X[i - 1] == Y[j - 1] == Z[k - 1]:
            lcs_chars.append(X[i - 1])
            i -= 1
            j -= 1
            k -= 1
        else:
            # Move to the neighbor with the maximum dp value
            if dp[i - 1][j][k] >= dp[i][j - 1][k] and dp[i - 1][j][k] >= dp[i][j][k - 1]:
                i -= 1
            elif dp[i][j - 1][k] >= dp[i - 1][j][k] and dp[i][j - 1][k] >= dp[i][j][k - 1]:
                j -= 1
            else:
                k -= 1
    return ''.join(reversed(lcs_chars))

