def count_rotation(arr):
    """
    Return the number of rotations required to sort a rotated sorted array.
    The rotation count equals the index of the minimum element.
    """
    if not arr:
        return 0
    low, high = 0, len(arr) - 1
    # If the array is not rotated (already sorted)
    if arr[low] <= arr[high]:
        return 0
    while low < high:
        mid = (low + high) // 2
        if arr[mid] > arr[high]:
            # Minimum is in the right half
            low = mid + 1
        else:
            # Minimum is in the left half (including mid)
            high = mid
    return low

