def count_reverse_pairs(test_list):
    from collections import Counter
    cnt = Counter(test_list)
    processed = set()
    pairs = 0
    for s in cnt:
        if s in processed:
            continue
        rev = s[::-1]
        if rev not in cnt:
            processed.add(s)
            continue
        if s == rev:
            n = cnt[s]
            pairs += n * (n - 1) // 2
        else:
            pairs += cnt[s] * cnt[rev]
        processed.add(s)
        processed.add(rev)
    return pairs

