    def clean(s):
        # Remove all parentheses and their contents, handling nested ones
        pattern = r'\([^()]*\)'
        while '(' in s:
            s, count = re.subn(pattern, '', s)
            if count == 0:
                break
        return s
    if isinstance(items, str):
        return clean(items)
    elif isinstance(items, (list, tuple)):
        return type(items)(clean(x) if isinstance(x, str) else x for x in items)
    else:
        return items

