def check_expression(exp):
    """
    This function checks if the given expression is balanced or not.
    """
    stack = []
    mapping = {")": "(", "}": "{", "]": "["}

    for char in exp:
        if char in mapping:
            top_element = stack.pop() if stack else '#'
            if mapping[char] != top_element:
                return False
        else:
            stack.append(char)

    return not stack
