def mul_even_odd(list1):
    """
    Finds the product of the first even and odd number of a given list.
    """
    even_num = None
    odd_num = None
    for num in list1:
        if num % 2 == 0 and even_num is None:
            even_num = num
        elif num % 2 != 0 and odd_num is None:
            odd_num = num
        if even_num is not None and odd_num is not None:
            break
    if even_num is None or odd_num is None:
        return None
    else:
        return even_num * odd_num
