def largest_subset(a):
    """
    Finds the size of the largest subset of a list of numbers so that every pair is divisible.
    """
    if not a:
        return 0

    n = len(a)
    max_size = 0

    for i in range(1 << n):
        subset = []
        for j in range(n):
            if (i >> j) & 1:
                subset.append(a[j])

        if not subset:
            continue

        is_divisible = True
        for k in range(len(subset)):
            for l in range(k + 1, len(subset)):
                if subset[k] % subset[l] != 0:
                    is_divisible = False
                    break
            if not is_divisible:
                break

        if is_divisible:
            max_size = max(max_size, len(subset))

    return max_size
```

