def lcs_of_three(X, Y, Z):
    """
    Finds the longest common subsequence of three strings.
    """
    n = len(X)
    m = len(Y)
    o = len(Z)

    L = [[[0 for k in range(o + 1)] for j in range(m + 1)] for i in range(n + 1)]

    for i in range(n + 1):
        for j in range(m + 1):
            for k in range(o + 1):
                if i == 0 or j == 0 or k == 0:
                    L[i][j][k] = 0
                elif X[i-1] == Y[j-1] and Y[j-1] == Z[k-1]:
                    L[i][j][k] = L[i-1][j-1][k-1] + 1
                else:
                    L[i][j][k] = max(L[i-1][j][k],
                                     L[i][j-1][k],
                                     L[i][j][k-1])

    length = L[n][m][o]
    result = ""
    i = n
    j = m
    k = o

    while i > 0 and j > 0 and k > 0:
        if X[i-1] == Y[j-1] and Y[j-1] == Z[k-1]:
            result = X[i-1] + result
            i -= 1
            j -= 1
            k -= 1
        else:
            if L[i-1][j][k] > L[i][j-1][k] and L[i-1][j][k] > L[i][j][k-1]:
                i -= 1
            elif L[i][j-1][k] > L[i-1][j][k] and L[i][j-1][k] > L[i][j][k-1]:
                j -= 1
            else:
                k -= 1
    return result
```

