def find_First_Missing(array, start=0, end=None):
    """
    Finds the smallest missing number from a sorted list of natural numbers.

    Args:
        array (list): A sorted list of natural numbers.
        start (int): The starting index of the array (default is 0).
        end (int): The ending index of the array (default is None, which means the end of the array).

    Returns:
        int: The smallest missing number in the array.
    """
    if end is None:
        end = len(array)

    if start > end:
        return 1

    for i in range(start, end):
        if array[i] != i + 1:
            return i + 1

    return end + 1
