def largest_subset(a):
    from collections import defaultdict

    def gcd(x, y):
        while y:
            x, y = y, x % y
        return x

    a.sort()
    n = len(a)
    size = [1] * n
    prev_index = [-1] * n

    for i in range(n):
        for j in range(i):
            if gcd(a[i], a[j]) == 1 and size[i] < size[j] + 1:
                size[i] = size[j] + 1
                prev_index[i] = j

    max_size = 0
    max_index = -1
    for i in range(n):
        if size[i] > max_size:
            max_size = size[i]
            max_index = i

    subset = []
    while max_index != -1:
        subset.append(a[max_index])
        max_index = prev_index[max_index]

    return len(subset)
