def lcs_of_three(X, Y, Z):
    m = len(X)
    n = len(Y)
    o = len(Z)

    # Create a 3D array to store lengths of longest common subsequence.
    L = [[[0 for k in range(o+1)] for j in range(n+1)] for i in range(m+1)]

    # Following steps build L[m+1][n+1][o+1] in bottom up fashion
    for i in range(m+1):
        for j in range(n+1):
            for k in range(o+1):
                if i == 0 or j == 0 or k == 0:
                    L[i][j][k] = 0
                elif X[i-1] == Y[j-1] and X[i-1] == Z[k-1]:
                    L[i][j][k] = L[i-1][j-1][k-1] + 1
                else:
                    L[i][j][k] = max(max(L[i-1][j][k], L[i][j-1][k]), L[i][j][k-1])

    # L[m][n][o] contains length of LCS for X[0..m-1], Y[0..n-1] and Z[0..o-1]
    return L[m][n][o]
