def maxAverageOfPath(cost):
    n = len(cost)
    dp = [[0] * n for _ in range(n)]

    for i in range(n):
        for j in range(n):
            if i == 0 and j == 0:
                dp[i][j] = cost[0][0]
            elif i == 0:
                dp[i][j] = dp[i][j-1] + cost[i][j]
            elif j == 0:
                dp[i][j] = dp[i-1][j] + cost[i][j]
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1]) + cost[i][j]

    return dp[-1][-1] / (2 * n - 1)
