```python
def rgb_to_hsv(r, g, b):
    # Normalize RGB values to [0, 1]
    r = r / 255.0
    g = g / 255.0
    b = b / 255.0

    # Find max and min
    v = max(r, g, b)
    min_rgb = min(r, g, b)

    # Calculate Value
    v = v

    # Calculate Saturation
    if v == 0:
        s = 0
    else:
        s = (v - min_rgb) / v

    # Calculate Hue
    if s == 0:
        h = 0
    else:
        if r == v:
            h = 60 * ((g - b) / s)
            if h < 0:
                h += 360
        elif g == v:
            h = 60 * ((b - r) / s) + 120
            if h >= 360:
                h -= 360
        else:
            h = 60 * ((r - g) / s) + 240
            if h >= 360:
                h -= 360

    return (h, s, v)
```

