def bell_Number(n):
    if n == 0:
        return 1

    def binomial(n, k):
        if k < 0 or k > n:
            return 0
        result = 1
        for i in range(k):
            result = result * (n - i) // (i + 1)
        return result

    bell = [0] * (n + 1)
    bell[0] = 1

    for i in range(1, n + 1):
        bell[i] = sum(binomial(i - 1, k) * bell[k] for k in range(i))

    return bell[n]
```

