```python
def lcs_of_three(X, Y, Z):
    """
    Finds the longest common subsequence for three strings.

    Args:
        X: The first string.
        Y: The second string.
        Z: The third string.

    Returns:
        The longest common subsequence of the three strings.
    """
    m = len(X)
    n = len(Y)
    o = len(Z)

    L = [[0] * (n + 1) for _ in range(m + 1)]
    S = [[0] * (n + 1) for _ in range(n + 1)]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            for k in range(1, o + 1):
                if X[i - 1] == Y[j - 1] and X[i - 1] == Z[k - 1]:
                    L[i][j] = L[i - 1][j - 1] + 1
                    S[i][j] = S[i - 1][j - 1] + 1
                else:
                    L[i][j] = max(L[i - 1][j], L[i][j - 1], L[i - 1][j - 1])
                    S[i][j] = S[i][j - 1] + 1

    def get_lcs(i, j):
        if i == 0 or j == 0:
            return ""
        if X[i - 1] == Y[j - 1] and X[i - 1] == Z[k - 1]:
            return X[i - 1] + get_lcs(i - 1, j - 1)
        else:
            return max(L[i - 1][j], L[i][j - 1], L[i - 1][j - 1]) + get_lcs(i - 1, j) + get_lcs(i, j - 1)

    return get_lcs(m, n)
