def maxAverageOfPath(cost):
    n = len(cost)
    if n == 0:
        return 0

    dp = {}

    def solve(row, col):
        if (row, col) in dp:
            return dp[(row, col)]

        if row == n - 1 and col == n - 1:
            return cost[row][col]

        if row >= n or col >= n:
            return float('-inf')

        down = solve(row + 1, col)
        right = solve(row, col + 1)

        if down == float('-inf') and right == float('-inf'):
            dp[(row, col)] = float('-inf')
        else:
            dp[(row, col)] = max(down, right)

        return dp[(row, col)]

    return solve(0, 0)
