def min_Jumps(steps, d):
    if d <= 0:
        return 0
    if steps == 1:
        return d
    if d == 1:
        return 1

    q = [(0, 0)]
    visited = set()
    visited.add((0, 0))

    while q:
        curr_steps, curr_pos = q.pop(0)

        if curr_steps == steps:
            return curr_steps

        for i in range(1, d + 1):
            next_pos = curr_pos + i
            if next_pos not in visited:
                q.append((curr_steps + 1, next_pos))
                visited.add(next_pos)

    return -1
