def check_min_heap_helper(arr, i):
    N = len(arr)

    # If index i is out of bounds, it means we traversed past a leaf node
    # or the initial call was invalid, but since we only call it on valid indices
    # or subsequent indices calculated based on valid parents, this primarily serves
    # as a guard.
    if i >= N:
        return True

    left = 2 * i + 1
    right = 2 * i + 2

    # 1. Check the Min Heap property at node i against its left child
    if left < N:
        if arr[i] > arr[left]:
            return False
        # Recursively check the left subtree
        if not check_min_heap_helper(arr, left):
            return False

    # 2. Check the Min Heap property at node i against its right child
    if right < N:
        if arr[i] > arr[right]:
            return False
        # Recursively check the right subtree
        if not check_min_heap_helper(arr, right):
            return False

    # If the current node i satisfies the property, and both subtrees are valid heaps
    return True

