def jacobsthal_num(n):
    if n < 0:
        raise ValueError("Input must be a non-negative integer.")

    if n == 0:
        return 0
    if n == 1:
        return 1

    # J_0 = 0
    # J_1 = 1

    # j_prev_prev stores J_{i-2}
    j_prev_prev = 0
    # j_prev stores J_{i-1}
    j_prev = 1

    # Start iteration from i = 2 up to n
    for i in range(2, n + 1):
        # J_i = J_{i-1} + 2 * J_{i-2}
        j_curr = j_prev + 2 * j_prev_prev

        # Update history for next iteration
        j_prev_prev = j_prev
        j_prev = j_curr

    return j_prev
