    for n in range(startnum, endnum + 1):
        original_n = n
        s_n = str(n)
        is_valid = True

        for char_digit in s_n:
            digit = int(char_digit)

            # A number cannot be divisible by 0.
            if digit == 0:
                is_valid = False
                break

            # Check if the number is divisible by the current digit
