def geometric_sum(n):
    if n < 2:
        return 0
    if n == 2:
        return 1
    # We calculate S(n) = 1 + 2 + 4 + ... + 2^(n-2)
    # The recursive step is S(n) = S(n-1) + 2^(n-2)
    # We use bit shifting (1 << k) to calculate 2^k.
    return geometric_sum(n - 1) + (1 << (n - 2))

