def find_min_diff(arr, n):
    if n < 2:
        return 0

    # Sort the array to ensure that the minimum difference must occur between adjacent elements
    arr.sort()

    min_diff = float('inf')

    # Iterate through the sorted array, checking the difference between adjacent elements
    for i in range(1, n):
        diff = arr[i] - arr[i-1]
        if diff < min_diff:
            min_diff = diff

    return min_diff

